using System;
using System.DirectoryServices;

public bool AuthenticateUser(string username, string password)
{
    // Prevent LDAP injection by using a secure way to construct the query
    var searchFilter = $"(&(objectClass=user)(sAMAccountName={username}))";
    var searchProperties = new[] { "dn", "memberOf" };

    // Use System.DirectoryServices to perform the LDAP query
    using (var directoryEntry = new DirectoryEntry("LDAP://your-ldap-server"))
    {
        using (var directorySearcher = new DirectorySearcher(directoryEntry))
        {
            directorySearcher.Filter = searchFilter;
            directorySearcher.PropertiesToLoad.AddRange(searchProperties);

            var results = directorySearcher.FindAll();
            if (results.Count == 0)
            {
                return false;
            }

            // Authenticate the user by checking their password
            var userEntry = results[0];
            using (var userDirectoryEntry = new DirectoryEntry(userEntry.Path, username, password))
            {
                if (userDirectoryEntry.NativeObject != null)
                {
                    return true;
                }
            }
        }
    }

    return false;
